    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Root(event_handler=handler)
        try:
            obj.__init__()
        except (TypeError, Exception):
            pass
        try:
            obj.__aenter__()
        except (TypeError, Exception):
            pass
        try:
            obj.__aexit__()
        except (TypeError, Exception):
            pass
        try:
            obj.run_pipeline()
        except (TypeError, Exception):
            pass
        try:
            obj._run_intake_stage()
        except (TypeError, Exception):
            pass
        try:
            obj._run_circuit_stage()
        except (TypeError, Exception):
            pass
        try:
            obj._run_assess_stage()
        except (TypeError, Exception):
            pass
        try:
            obj._run_format_and_seal_stage()
        except (TypeError, Exception):
            pass
        try:
            obj._build_pipeline_result()
        except (TypeError, Exception):
            pass
        try:
            obj._emit_event()
        except (TypeError, Exception):
            pass
        try:
            obj.create_root()
        except (TypeError, Exception):
            pass
        try:
            obj.map_decision_to_exit_code()
        except (TypeError, Exception):
            pass
        try:
            obj.get_config()
        except (TypeError, Exception):
            pass
        try:
            obj.get_circuit_router()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:root:"), f"Bad pact_key: {key}"

